implementation.code_pattern:
// Good: Focused signal
count := CreateSignal(0)

// Bad: Complex state object
state := CreateSignal(ComplexState{...})

// Good: Pure effect
CreateEffect(func() {
    dom.SetTextContent(element, count.Get())
})

// Bad: Side effects without clear dependencies
CreateEffect(func() {
    // Multiple unrelated side effects
})

// Good: Direct DOM binding
CreateEffect(func() {
    element.Set("textContent", value.Get())
})

// Bad: Virtual DOM approach
render := func() VNode { return h("div", value.Get()) }
